import numpy as np

def get_lr_cosine(step: int, total_steps: int, lr_max: float,
                  lr_min: float = 0.0, warmup_steps: int = 0) -> float:
    if step < warmup_steps:
        return float(lr_max * step / max(warmup_steps, 1))
    progress = (step - warmup_steps) / max(total_steps - warmup_steps, 1)
    return float(lr_min + 0.5 * (lr_max - lr_min) * (1 + np.cos(np.pi * progress)))
